// src/server/routers/user.ts
export const userRouter = router({
  profile: protectedProcedure
    .input(z.object({ id: z.string() }))
    .query(async ({ input, ctx }) => {
      return ctx.db.user.findUnique({
        where: { id: input.id },
        select: { name: true, email: true }
      });
    })
});
